// Ground the Lie bracket: compute A B A⁻¹ B⁻¹ and see what's left over.

const mul = (A, B) =>
  A.map((row, i) =>
    B[0].map((_, j) => row.reduce((s, a, k) => s + a * B[k][j], 0)),
  );
const chain = (...Ms) => Ms.reduce(mul);
const sub = (A, B) => A.map((r, i) => r.map((a, j) => a - B[i][j]));
const maxAbs = (A) => Math.max(...A.flat().map(Math.abs));
const show = (A) =>
  A.map((r) => r.map((x) => x.toFixed(6).padStart(10)).join(' ')).join('\n');

const Rx = (t) => [
  [1, 0, 0],
  [0, Math.cos(t), -Math.sin(t)],
  [0, Math.sin(t), Math.cos(t)],
];
const Ry = (t) => [
  [Math.cos(t), 0, Math.sin(t)],
  [0, 1, 0],
  [-Math.sin(t), 0, Math.cos(t)],
];
const Rz = (t) => [
  [Math.cos(t), -Math.sin(t), 0],
  [Math.sin(t), Math.cos(t), 0],
  [0, 0, 1],
];

const eps = 0.1;

// Commutator of small rotations about x and y
const C = chain(Rx(eps), Ry(eps), Rx(-eps), Ry(-eps));
console.log(`ε = ${eps}\n`);
console.log('C = Rx(ε) Ry(ε) Rx(-ε) Ry(-ε):');
console.log(show(C));
console.log('\nRz(ε²) for comparison:');
console.log(show(Rz(eps * eps)));
console.log(`\nmax |C - Rz(ε²)|      = ${maxAbs(sub(C, Rz(eps * eps))).toExponential(3)}`);
console.log(`max |C - I|           = ${maxAbs(sub(C, Rz(0))).toExponential(3)}  (size of the residue itself)`);

// Scaling check: residue should shrink like ε², error like ε³
console.log('\nscaling of the residue with ε:');
for (const e of [0.2, 0.1, 0.05, 0.025]) {
  const Ce = chain(Rx(e), Ry(e), Rx(-e), Ry(-e));
  const resid = maxAbs(sub(Ce, Rz(0)));
  const err = maxAbs(sub(Ce, Rz(e * e)));
  console.log(
    `ε=${e.toFixed(3)}  |C-I|=${resid.toExponential(2)}  (ε²=${(e * e).toExponential(2)})  |C-Rz(ε²)|=${err.toExponential(2)}  (ε³=${(e ** 3).toExponential(2)})`,
  );
}

